#!/usr/bin/env python3
"""
DinoSAT — Convert verification report markdown to branded PDF.

Usage:
    python3 generate_pdf.py DINOSAT_REPORT.md [output.pdf]

Requires: pip install fpdf2
"""

import sys
import os
import re
import base64
from pathlib import Path


def check_dependencies():
    try:
        import fpdf
    except ImportError:
        print("Missing: fpdf2")
        print("Install: pip install fpdf2")
        sys.exit(1)

# Embedded logo (base64-encoded PNG — never changes)
_LOGO_B64 = """

"""


def _get_logo_bytes():
    """Decode the embedded logo and return raw bytes (accepted by fpdf2's image())."""
    return base64.b64decode(_LOGO_B64)

# Brand palette
BRAND = (11, 12, 14)          # #0B0C0E — primary dark
BRAND_ACCENT = (34, 197, 94)  # #22C55E — accent green (for cover accents)
BRAND_LIGHT = (55, 65, 81)    # #374151
GRAY = (107, 114, 128)        # #6b7280
GRAY_LIGHT = (156, 163, 175)  # #9CA3AF
TEXT = (31, 41, 55)            # #1f2937
WHITE = (255, 255, 255)
GREEN = (5, 150, 105)
BLUE = (37, 99, 235)
RED = (220, 38, 38)
AMBER = (217, 119, 6)
CODE_BG = (30, 41, 59)
CODE_FG = (226, 232, 240)
TABLE_HEAD = (11, 12, 14)
TABLE_EVEN = (249, 250, 251)
TABLE_ODD = (255, 255, 255)


def _extract_metadata(md_text):
    """Extract protocol name, date, and other metadata from the markdown H1 and bold fields."""
    meta = {"protocol": "", "date": ""}
    for line in md_text.split("\n"):
        if line.startswith("# ") and not line.startswith("## "):
            # "# Protocol Name — Formal Verification Report"
            title = line[2:].strip()
            if "—" in title or "--" in title:
                sep = "—" if "—" in title else "--"
                meta["protocol"] = title.split(sep)[0].strip()
            elif "-" in title:
                meta["protocol"] = title.split("-")[0].strip()
            else:
                meta["protocol"] = title
        elif line.strip().startswith("**Date:**"):
            meta["date"] = line.split(":**", 1)[-1].strip().strip("*").strip()
    return meta


class DinoSATPDF:
    def __init__(self, logo_bytes=None):
        from fpdf import FPDF

        _logo = logo_bytes

        class PDF(FPDF):
            def header(self):
                # Thin brand line at top
                self.set_draw_color(*BRAND)
                self.set_line_width(0.6)
                self.line(10, 10, self.w - 10, 10)
                # Logo mark (small) on the left
                if _logo:
                    try:
                        self.image(_logo, x=10, y=12, h=6)
                    except Exception:
                        pass
                # "DinoSAT" text on the right
                self.set_font("Helvetica", "B", 7)
                self.set_text_color(*GRAY)
                self.set_xy(self.w - 50, 11)
                self.cell(40, 5, "DinoSAT | Formal Verification", align="R")
                self.set_y(22)

            def footer(self):
                self.set_y(-15)
                self.set_draw_color(220, 220, 220)
                self.set_line_width(0.3)
                self.line(10, self.h - 17, self.w - 10, self.h - 17)
                self.set_font("Helvetica", "", 7)
                self.set_text_color(*GRAY)
                self.cell(0, 10, f"Page {self.page_no()}/{{nb}}", align="C")
                self.set_x(-70)
                self.cell(60, 10, "Generated by DinoSAT | dinosat.com", align="R")

        self.pdf = PDF()
        self.pdf.alias_nb_pages()
        self.pdf.set_auto_page_break(auto=True, margin=25)
        self.pdf.set_font("Helvetica", size=10)
        self.logo_bytes = logo_bytes

    def add_cover(self, meta):
        """Branded cover page — clean, centered layout."""
        self.pdf.add_page()
        self.pdf.set_y(40)

        # Logo (centered)
        if self.logo_bytes:
            try:
                self.pdf.image(self.logo_bytes, x=75, y=30, w=60)
                self.pdf.set_y(95)
            except Exception:
                self.pdf.set_y(50)
        else:
            self.pdf.set_y(50)

        # "DinoSAT" title
        self.pdf.set_font("Helvetica", "B", 36)
        self.pdf.set_text_color(*BRAND)
        self.pdf.cell(0, 16, "DinoSAT", align="C", new_x="LMARGIN", new_y="NEXT")

        # Subtitle
        self.pdf.set_font("Helvetica", "", 11)
        self.pdf.set_text_color(*GRAY)
        self.pdf.cell(0, 8, "FORMAL VERIFICATION REPORT", align="C", new_x="LMARGIN", new_y="NEXT")

        # Accent line (centered, short)
        self.pdf.ln(8)
        cx = self.pdf.w / 2
        self.pdf.set_draw_color(*BRAND_ACCENT)
        self.pdf.set_line_width(1.2)
        self.pdf.line(cx - 30, self.pdf.get_y(), cx + 30, self.pdf.get_y())
        self.pdf.ln(14)

        # Protocol name
        protocol = meta.get("protocol", "")
        if protocol:
            self.pdf.set_font("Helvetica", "B", 24)
            self.pdf.set_text_color(*BRAND)
            self.pdf.cell(0, 12, self._clean(protocol), align="C", new_x="LMARGIN", new_y="NEXT")
            self.pdf.ln(4)

        # Date
        date = meta.get("date", "")
        if date:
            self.pdf.set_font("Helvetica", "", 11)
            self.pdf.set_text_color(*GRAY)
            self.pdf.cell(0, 8, self._clean(date), align="C", new_x="LMARGIN", new_y="NEXT")

        # Bottom — URL (disable auto page break to prevent overflow to next page)
        self.pdf.set_auto_page_break(auto=False)
        self.pdf.set_y(self.pdf.h - 28)
        self.pdf.set_font("Helvetica", "", 9)
        self.pdf.set_text_color(*GRAY)
        self.pdf.cell(0, 8, "https://dinosat.com", align="C", new_x="LMARGIN", new_y="NEXT")
        self.pdf.set_text_color(*TEXT)
        self.pdf.set_auto_page_break(auto=True, margin=25)

    def add_toc(self, md_text):
        """Add a Table of Contents page by scanning the markdown for H2/H3 headings."""
        headings = []
        in_code = False
        for line in md_text.split("\n"):
            if line.strip().startswith("```"):
                in_code = not in_code
                continue
            if in_code:
                continue
            if line.startswith("## ") and not line.startswith("### "):
                headings.append((2, self._clean(line[3:].strip())))
            elif line.startswith("### ") and not line.startswith("#### "):
                headings.append((3, self._clean(line[4:].strip())))

        if not headings:
            return

        self.pdf.add_page()
        self.pdf.set_font("Helvetica", "B", 22)
        self.pdf.set_text_color(*BRAND)
        self.pdf.cell(0, 14, "Table of Contents", new_x="LMARGIN", new_y="NEXT")
        self.pdf.ln(4)
        self.pdf.set_draw_color(*BRAND)
        self.pdf.set_line_width(0.6)
        self.pdf.line(10, self.pdf.get_y(), 60, self.pdf.get_y())
        self.pdf.ln(8)

        for level, title in headings:
            if level == 2:
                self.pdf.set_font("Helvetica", "B", 10)
                self.pdf.set_text_color(*BRAND)
                indent = 10
                self.pdf.ln(1.5)
            else:
                self.pdf.set_font("Helvetica", "", 9)
                self.pdf.set_text_color(*BRAND_LIGHT)
                indent = 20
            self.pdf.set_x(indent)
            self.pdf.cell(0, 5.5, title, new_x="LMARGIN", new_y="NEXT")
            self.pdf.ln(0.8)

        self.pdf.set_text_color(*TEXT)

    def parse_and_render(self, md_text):
        lines = md_text.split("\n")
        i = 0
        in_code = False
        code_buf = []
        tbl_buf = []
        in_tbl = False

        while i < len(lines):
            line = lines[i]

            # Code blocks
            if line.strip().startswith("```"):
                if in_code:
                    self._render_code(code_buf)
                    code_buf = []
                    in_code = False
                else:
                    if in_tbl:
                        self._render_table(tbl_buf)
                        tbl_buf = []
                        in_tbl = False
                    in_code = True
                i += 1
                continue
            if in_code:
                code_buf.append(line)
                i += 1
                continue

            # Tables
            if "|" in line and line.strip().startswith("|"):
                stripped = line.strip().replace("|", "").replace("-", "").replace(":", "").replace(" ", "")
                if stripped == "":
                    i += 1
                    continue
                if not in_tbl:
                    in_tbl = True
                tbl_buf.append(line)
                i += 1
                continue
            elif in_tbl:
                self._render_table(tbl_buf)
                tbl_buf = []
                in_tbl = False

            # H1 — skip (cover handles it)
            if line.startswith("# ") and not line.startswith("## "):
                i += 1
                continue

            # H2 — major section heading
            elif line.startswith("## "):
                # Only break to new page if current page is more than half full
                if self.pdf.get_y() > self.pdf.h * 0.45:
                    self.pdf.add_page()
                else:
                    self.pdf.ln(6)
                self.pdf.set_font("Helvetica", "B", 16)
                self.pdf.set_text_color(*BRAND)
                self.pdf.cell(0, 10, self._clean(line[3:].strip()), new_x="LMARGIN", new_y="NEXT")
                # Accent underline (short, brand-colored)
                self.pdf.set_draw_color(*BRAND)
                self.pdf.set_line_width(0.7)
                self.pdf.line(10, self.pdf.get_y() + 1, 60, self.pdf.get_y() + 1)
                self.pdf.ln(6)
                self.pdf.set_text_color(*TEXT)

            # H3
            elif line.startswith("### "):
                self._space(22)
                self.pdf.ln(5)
                self.pdf.set_font("Helvetica", "B", 12)
                self.pdf.set_text_color(*BRAND_LIGHT)
                self.pdf.cell(0, 8, self._clean(line[4:].strip()), new_x="LMARGIN", new_y="NEXT")
                self.pdf.set_text_color(*TEXT)
                self.pdf.ln(3)

            # H4
            elif line.startswith("#### "):
                self._space(15)
                self.pdf.ln(2)
                self.pdf.set_font("Helvetica", "B", 10.5)
                self.pdf.set_text_color(*BRAND_LIGHT)
                self.pdf.cell(0, 7, self._clean(line[5:].strip()), new_x="LMARGIN", new_y="NEXT")
                self.pdf.set_text_color(*TEXT)
                self.pdf.ln(2)

            # HR
            elif line.strip() == "---":
                self.pdf.ln(4)
                self.pdf.set_draw_color(220, 220, 220)
                self.pdf.set_line_width(0.3)
                self.pdf.line(10, self.pdf.get_y(), self.pdf.w - 10, self.pdf.get_y())
                self.pdf.ln(4)

            # Blockquote
            elif line.strip().startswith("> "):
                self._render_blockquote(line.strip()[2:])

            # List item
            elif line.strip().startswith("- "):
                self._render_list_item(line)

            # Metadata (bold key: value)
            elif line.strip().startswith("**") and ":**" in line:
                self._render_metadata_line(line.strip())

            # Paragraph
            elif line.strip():
                self.pdf.set_font("Helvetica", "", 10)
                self.pdf.multi_cell(0, 5.5, self._clean(line.strip()))
                self.pdf.ln(1.5)

            # Blank
            else:
                self.pdf.ln(2)

            i += 1

        if in_tbl and tbl_buf:
            self._render_table(tbl_buf)
        if in_code and code_buf:
            self._render_code(code_buf)

    def _space(self, mm):
        if self.pdf.get_y() + mm > self.pdf.h - 25:
            self.pdf.add_page()

    def _clean(self, text):
        text = re.sub(r"\*\*(.+?)\*\*", r"\1", text)
        text = re.sub(r"\*(.+?)\*", r"\1", text)
        text = re.sub(r"`(.+?)`", r"\1", text)
        text = re.sub(r"\[(.+?)\]\(.+?\)", r"\1", text)
        # Unicode -> ASCII replacements for Latin-1 safe output.
        # Helvetica (core PDF font) only supports Latin-1. Characters not in
        # this table and outside Latin-1 are replaced with '?' by the
        # encode("latin-1", errors="replace") call below.
        replacements = {
            "\u2014": "--", "\u2013": "-", "\u2018": "'", "\u2019": "'",
            "\u201c": '"', "\u201d": '"', "\u2022": "-", "\u2026": "...",
            "\u2264": "<=", "\u2265": ">=", "\u2260": "!=",
            "\u2192": "->", "\u2190": "<-", "\u2194": "<->",
            "\u2248": "~=", "\u2261": "===", "\u2227": "&&", "\u2228": "||",
            "\u00d7": "x", "\u00f7": "/", "\u2212": "-",
            "\u2713": "[PASS]", "\u2717": "[FAIL]", "\u2714": "[PASS]", "\u2716": "[FAIL]",
            "\u25b8": ">", "\u25cb": "o", "\u2588": "#", "\u2591": ".",
            "\u221e": "inf", "\u2200": "forall", "\u2203": "exists",
            "\u2208": "in", "\u2209": "not in", "\u2286": "<=", "\u2287": ">=",
        }
        for k, v in replacements.items():
            text = text.replace(k, v)
        return text.encode("latin-1", errors="replace").decode("latin-1")

    def _render_metadata_line(self, line):
        """Render **Key:** Value as a structured two-part line."""
        clean = self._clean(line)
        # Split on first colon
        if ":" in clean:
            key, val = clean.split(":", 1)
            key = key.strip()
            val = val.strip()
        else:
            key = clean
            val = ""
        self.pdf.set_font("Helvetica", "B", 9)
        self.pdf.set_text_color(*BRAND_LIGHT)
        self.pdf.cell(45, 5.5, key + ":", new_x="RIGHT", new_y="TOP")
        self.pdf.set_font("Helvetica", "", 9)
        self.pdf.set_text_color(*TEXT)
        self.pdf.cell(0, 5.5, val, new_x="LMARGIN", new_y="NEXT")
        self.pdf.ln(0.5)

    def _render_list_item(self, line):
        indent = len(line) - len(line.lstrip())
        clean = self._clean(line.strip()[2:])
        self.pdf.set_font("Helvetica", "", 9)
        x = 14 + (indent * 2)
        self.pdf.set_x(x)

        if "[PASS]" in clean:
            self.pdf.set_text_color(*GREEN)
            marker = "- "
        elif "[FUZZ]" in clean:
            self.pdf.set_text_color(*BLUE)
            marker = "- "
        elif "[COUNTEREXAMPLE]" in clean or "[FAIL]" in clean:
            self.pdf.set_text_color(*RED)
            marker = "- "
        else:
            self.pdf.set_text_color(*TEXT)
            marker = "- "

        self.pdf.multi_cell(self.pdf.w - x - 10, 4.8, marker + clean)
        self.pdf.set_text_color(*TEXT)
        self.pdf.ln(0.8)

    def _render_code(self, lines):
        self._space(len(lines) * 4 + 12)
        self.pdf.set_fill_color(*CODE_BG)
        self.pdf.set_text_color(*CODE_FG)
        self.pdf.set_font("Courier", "", 7)
        w = self.pdf.w - 20
        # Top padding
        self.pdf.set_x(10)
        self.pdf.cell(w, 2, "", fill=True, new_x="LMARGIN", new_y="NEXT")
        for ln in lines:
            if self.pdf.get_y() > self.pdf.h - 28:
                self.pdf.add_page()
            self.pdf.set_x(10)
            safe = self._clean(ln[:130])  # truncate to fit A4 page width
            self.pdf.cell(w, 3.8, "  " + safe, fill=True, new_x="LMARGIN", new_y="NEXT")
        # Bottom padding
        self.pdf.set_x(10)
        self.pdf.cell(w, 2, "", fill=True, new_x="LMARGIN", new_y="NEXT")
        self.pdf.set_text_color(*TEXT)
        self.pdf.ln(4)

    def _render_table(self, rows):
        if not rows:
            return
        self._space(len(rows) * 7 + 12)

        parsed = []
        for row in rows:
            cells = [c.strip() for c in row.strip().strip("|").split("|")]
            parsed.append(cells)
        if not parsed:
            return

        n_cols = len(parsed[0])
        page_w = self.pdf.w - 20
        pad = 4  # horizontal cell padding (mm)

        # Measure actual rendered width per column (accounts for proportional font)
        self.pdf.set_font("Helvetica", "B", 7.5)
        max_widths = [0.0] * n_cols
        for row in parsed:
            for j, cell in enumerate(row):
                if j < n_cols:
                    w = self.pdf.get_string_width(self._clean(cell)) + pad
                    max_widths[j] = max(max_widths[j], w)
        total_w = max(sum(max_widths), 1)
        # Scale columns to fill the page width
        col_widths = [page_w * (mw / total_w) for mw in max_widths]

        # Header
        self.pdf.set_font("Helvetica", "B", 7.5)
        self.pdf.set_fill_color(*TABLE_HEAD)
        self.pdf.set_text_color(*WHITE)
        for j, cell in enumerate(parsed[0]):
            w = col_widths[j] if j < len(col_widths) else 20
            self.pdf.cell(w, 6.5, self._clean(cell), border=0, fill=True)
        self.pdf.ln()

        # Data rows
        self.pdf.set_font("Helvetica", "", 7.5)
        for idx, row in enumerate(parsed[1:]):
            if self.pdf.get_y() > self.pdf.h - 28:
                self.pdf.add_page()
            bg = TABLE_EVEN if idx % 2 == 0 else TABLE_ODD
            self.pdf.set_fill_color(*bg)

            for j, cell in enumerate(row):
                w = col_widths[j] if j < len(col_widths) else 20
                clean = self._clean(cell)
                # Status-aware coloring
                s = clean.strip()
                if s.startswith("PROVEN") or "ALL PROVEN" in s:
                    self.pdf.set_text_color(*GREEN)
                elif s.startswith("FUZZ") or "ALL VERIFIED" in s:
                    self.pdf.set_text_color(*BLUE)
                elif "COUNTEREXAMPLE" in s:
                    self.pdf.set_text_color(*RED)
                elif s.startswith("TIMEOUT"):
                    self.pdf.set_text_color(*AMBER)
                else:
                    self.pdf.set_text_color(*TEXT)
                self.pdf.cell(w, 5.5, clean, border=0, fill=True)
            self.pdf.ln()
            # Subtle row separator
            self.pdf.set_draw_color(235, 235, 235)
            self.pdf.set_line_width(0.1)
            self.pdf.line(10, self.pdf.get_y(), self.pdf.w - 10, self.pdf.get_y())

        self.pdf.set_text_color(*TEXT)
        self.pdf.ln(4)

    def _render_blockquote(self, text):
        self._space(14)
        clean = self._clean(text)

        # Detect severity-based coloring
        if "VULNERABILITIES" in clean or "COUNTEREXAMPLE" in clean:
            bar_color = RED
            bg_color = (254, 242, 242)
            text_color = (153, 27, 27)
        elif "P0" in clean or "CRITICAL" in clean:
            bar_color = AMBER
            bg_color = (255, 251, 235)
            text_color = (146, 64, 14)
        else:
            bar_color = BLUE
            bg_color = (239, 246, 255)
            text_color = (30, 64, 175)

        self.pdf.set_fill_color(*bg_color)
        self.pdf.set_text_color(*text_color)
        self.pdf.set_font("Helvetica", "", 9)

        # Calculate height for the blockquote
        y_start = self.pdf.get_y()
        self.pdf.set_x(18)
        self.pdf.multi_cell(self.pdf.w - 28, 5.5, clean, fill=True)
        y_end = self.pdf.get_y()

        # Left accent bar
        self.pdf.set_draw_color(*bar_color)
        self.pdf.set_line_width(1.5)
        self.pdf.line(14, y_start, 14, y_end)

        self.pdf.set_text_color(*TEXT)
        self.pdf.set_line_width(0.2)
        self.pdf.ln(3)

    def save(self, path):
        self.pdf.output(path)





def main():
    if len(sys.argv) < 2:
        print("Usage: python3 generate_pdf.py <report.md> [output.pdf]")
        sys.exit(1)

    check_dependencies()

    md_path = sys.argv[1]
    if not os.path.exists(md_path):
        print(f"Error: {md_path} not found")
        sys.exit(1)

    output_path = sys.argv[2] if len(sys.argv) >= 3 else Path(md_path).stem + ".pdf"
    md_text = Path(md_path).read_text()
    logo_bytes = _get_logo_bytes()
    meta = _extract_metadata(md_text)

    doc = DinoSATPDF(logo_bytes)
    doc.add_cover(meta)
    doc.add_toc(md_text)
    doc.parse_and_render(md_text)
    doc.save(output_path)
    print(f"PDF generated: {output_path}")


if __name__ == "__main__":
    main()
